export const nextGeneration = (cells: Set<string>): Set<string> => {
  const neighborCounts = countLiveNeighbors(cells);
  const survivingCells = [...neighborCounts].filter(([cell, count]) =>
    cellLivesNextGeneration(count, cells.has(cell))
  );
  return new Set(survivingCells.map(([cell]) => cell));
};

